import React, { useState, useEffect, useRef } from 'react';
import { MessageSquare, Send, X, Bot, AlertCircle } from 'lucide-react';
import { askAssistant } from '../services/geminiService';

const Assistant: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<{ role: 'user' | 'bot' | 'error'; text: string }[]>([
    { role: 'bot', text: 'Olá! Sou o assistente da Fazenda Vitória Francisco. Como posso ajudar com sua produção hoje?' }
  ]);
  const [loading, setLoading] = useState(false);
  const isMounted = useRef(true);

  useEffect(() => {
    isMounted.current = true;
    return () => {
      isMounted.current = false;
    };
  }, []);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setLoading(true);

    try {
      const response = await askAssistant(userMsg);

      if (isMounted.current) {
        setMessages(prev => [...prev, { role: 'bot', text: response }]);
      }
    } catch (err) {
      console.error("Chat Error:", err);
      if (isMounted.current) {
        setMessages(prev => [...prev, { 
          role: 'error', 
          text: 'Não foi possível conectar ao assistente. Verifique sua conexão ou tente novamente mais tarde.' 
        }]);
      }
    } finally {
      if (isMounted.current) {
        setLoading(false);
      }
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-50">
      {!isOpen && (
        <button
          onClick={() => setIsOpen(true)}
          className="bg-[#DAA520] hover:bg-[#C0941C] text-white p-4 rounded-full shadow-lg transition-transform hover:scale-110 flex items-center space-x-2"
        >
          <MessageSquare className="w-6 h-6" />
          <span className="hidden sm:inline font-semibold">Dúvida no campo?</span>
        </button>
      )}

      {isOpen && (
        <div className="bg-white rounded-2xl shadow-2xl w-80 sm:w-96 border border-gray-200 overflow-hidden flex flex-col max-h-[500px] animate-scale-up">
          <div className="bg-[#4A5D23] p-4 flex justify-between items-center">
            <div className="flex items-center space-x-2 text-white">
              <Bot className="w-5 h-5" />
              <span className="font-bold">Assistente Agrícola</span>
            </div>
            <button onClick={() => setIsOpen(false)} className="text-white hover:text-gray-200">
              <X className="w-5 h-5" />
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50">
            {messages.map((msg, idx) => (
              <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-3 rounded-2xl text-sm shadow-sm ${
                  msg.role === 'user' 
                    ? 'bg-[#DAA520] text-white rounded-tr-none' 
                    : msg.role === 'error'
                    ? 'bg-red-50 text-red-700 border border-red-100 flex items-center'
                    : 'bg-white text-gray-800 border border-gray-100 rounded-tl-none'
                }`}>
                  {msg.role === 'error' && <AlertCircle className="w-4 h-4 mr-2 flex-shrink-0" />}
                  {msg.text}
                </div>
              </div>
            ))}
            {loading && (
              <div className="flex justify-start">
                <div className="bg-white border border-gray-100 p-3 rounded-2xl rounded-tl-none text-sm animate-pulse text-gray-400 flex items-center">
                  <span className="flex space-x-1">
                    <span className="w-1.5 h-1.5 bg-gray-300 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></span>
                    <span className="w-1.5 h-1.5 bg-gray-300 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></span>
                    <span className="w-1.5 h-1.5 bg-gray-300 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></span>
                  </span>
                </div>
              </div>
            )}
          </div>

          <div className="p-4 border-t border-gray-100 bg-white flex space-x-2">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Pergunte sobre plantio..."
              disabled={loading}
              className="flex-1 border border-gray-200 rounded-xl px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-[#4A5D23] disabled:bg-gray-50"
            />
            <button
              onClick={handleSend}
              disabled={loading}
              className="bg-[#4A5D23] text-white p-2.5 rounded-xl hover:bg-[#2D3B16] transition-colors disabled:opacity-50"
            >
              <Send className="w-4 h-4" />
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default Assistant;

import { GoogleGenAI } from "@google/genai";

// Inicialização segura
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function askAssistant(question: string) {
  try {
    const sanitizedQuestion = question.replace(/[<>]/g, '').trim().slice(0, 500);
    if (!sanitizedQuestion) return "Como posso ajudar?";

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: sanitizedQuestion,
      config: {
        systemInstruction: `Você é o Assistente Virtual da Fazenda Vitória Francisco. 
        REGRAS:
        1. Fale sobre Avicultura, Agricultura, Suinocultura e Insumos em Angola.
        2. Seja cordial e técnico.
        3. Recuse pedidos de código ou dados sensíveis.
        4. Não use Markdown complexo ou HTML.`,
        temperature: 0.3,
      }
    });

    // Verificação robusta da existência da propriedade text
    const text = response.text;
    if (!text) {
      throw new Error("Empty response from Gemini");
    }

    return text;
  } catch (error: any) {
    console.warn("Gemini Service Error:", error.message || error);

    // Mensagens de erro amigáveis baseadas em falhas comuns
    if (error.message?.includes("fetch") || error.message?.includes("channel")) {
      return "Houve uma instabilidade na conexão. Por favor, tente enviar sua mensagem novamente.";
    }

    return "Desculpe, tive um problema técnico. Pode repetir a pergunta de forma mais simples?";
  }
}

